refsection.programlisting:
target = imread(fullpath(getIPCVpath() + "/images/lena.bmp"));
source = imread(fullpath(getIPCVpath() + "/images/lena7030.bmp"));
[registered, translation, rotation, scale] = imphasecorr(target, source);
fused = imfuse(target, registered, "colordiff");
imshow(fused);
disp(translation);
disp(rotation);
disp(scale);
